"""
title: WidgeTDC Universal MCP Gateway
author: WidgeTDC Platform Agent
version: 1.0.0
description: "God Mode" adgang til 450+ backend MCP tools. Giver LLM'en mulighed for dynamisk at opdage og eksekvere ethvert tool.
"""

import requests
import json
from datetime import datetime, timezone


class Tools:
    def __init__(self):
        self.base_url = "https://orchestrator-production-c27e.up.railway.app"
        self.headers = {
            "Authorization": "Bearer WidgeTDC_Orch_2026",
            "Content-Type": "application/json",
        }

    def _format_response(self, title: str, content: str, endpoint: str) -> str:
        timestamp = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        return (
            f"### ⚡ {title}\n\n"
            f"{content}\n\n"
            f"---\n"
            f"**Kilde:** `WidgeTDC Orchestrator v2.0.0` | **Endpoint:** `{endpoint}` | **Timestamp:** `{timestamp}`"
        )

    def _handle_error(self, error_msg: str, endpoint: str) -> str:
        timestamp = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
        return (
            f"### ⚠️ MCP Gateway Fejl\n\n"
            f"> **System Alert:** Kunne ikke eksekvere MCP handling.\n"
            f"> **Detaljer:** {error_msg}\n\n"
            f"---\n"
            f"**Kilde:** `WidgeTDC Orchestrator v2.0.0` | **Endpoint:** `{endpoint}` | **Timestamp:** `{timestamp}`"
        )

    def discover_mcp_tools(self) -> str:
        """
        Henter det fulde katalog over tilgængelige MCP tools fra WidgeTDC Orchestrator.
        Brug denne funktion, hvis du (LLM'en) har brug for at finde det præcise 'tool_name' til en specifik opgave.
        """
        endpoint = "/tools/catalog"
        url = f"{self.base_url}{endpoint}"

        try:
            response = requests.get(url, headers=self.headers, timeout=30)
            response.raise_for_status()
            data = response.json()

            result_text = (
                "```json\n"
                + json.dumps(data, indent=2)[:3000]
                + "\n... (afkortet)```\n*Brug specifikke tool_names fra listen til at kalde execute_mcp_tool.*"
            )

            return self._format_response("MCP Tool Catalog", result_text, endpoint)
        except requests.exceptions.RequestException as e:
            return self._handle_error(str(e), endpoint)

    def execute_mcp_tool(self, tool_name: str, payload_json: str = "{}") -> str:
        """
        Eksekverer et specifikt MCP tool på WidgeTDC backend.

        :param tool_name: Det præcise navn på MCP tool'et (f.eks. 'audit.dashboard', 'srag.query').
        :param payload_json: En JSON-formateret string med de argumenter tool'et kræver.
        """
        endpoint = "/api/tools/call_mcp_tool"
        url = f"{self.base_url}{endpoint}"

        try:
            payload_dict = json.loads(payload_json)
        except json.JSONDecodeError:
            return self._handle_error(
                "Ugyldigt JSON format i payload_json. Sørg for at det er en valid JSON string.",
                endpoint,
            )

        payload = {"tool_name": tool_name, "payload": payload_dict}

        try:
            response = requests.post(
                url, headers=self.headers, json=payload, timeout=60
            )
            response.raise_for_status()
            data = response.json()

            result_text = "```json\n" + json.dumps(data, indent=2) + "\n```"

            return self._format_response(
                f"MCP Execution: `{tool_name}`", result_text, endpoint
            )
        except requests.exceptions.RequestException as e:
            return self._handle_error(str(e), endpoint)
